func trackRequest(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "anonymous"
	}

	endpoint := r.URL.Path
	method := r.Method
	requestID := generateRequestID()

	activeRequests.WithLabelValues(userID, endpoint, method).Inc()
	defer activeRequests.WithLabelValues(userID, endpoint, method).Dec()

	start := time.Now()
	defer func() {
		duration := time.Since(start).Seconds()
		status := "200"
		requestCounter.WithLabelValues(userID, endpoint, method, status, requestID).Inc()
		requestDuration.WithLabelValues(userID, endpoint, method, status, requestID).Observe(duration)
	}()

	dataSize := rand.Float64() * 10000
	dataType := r.URL.Query().Get("data_type")
	if dataType == "" {
		dataType = "json"
	}
	operation := r.URL.Query().Get("operation")
	if operation == "" {
		operation = "read"
	}
	source := r.URL.Query().Get("source")
	if source == "" {
		source = "api"
	}
	userDataProcessed.WithLabelValues(userID, dataType, operation, source).Add(dataSize)

	service := r.URL.Query().Get("service")
	if service == "" {
		service = "default"
	}
	clientVersion := r.URL.Query().Get("client_version")
	if clientVersion == "" {
		clientVersion = "1.0.0"
	}
	processingTime := rand.Float64() * 0.5
	perRequestMetric.WithLabelValues(userID, requestID, service, operation, clientVersion).Observe(processingTime)

	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Request tracked for user: %s, request_id: %s\n", userID, requestID)
}

