		endpoint := endpoints[rand.Intn(len(endpoints))]
		method := methods[rand.Intn(len(methods))]
		requestID := generateRequestID()
		status := "200"

		requestCounter.WithLabelValues(userID, endpoint, method, status, requestID).Inc()
		requestDuration.WithLabelValues(userID, endpoint, method, status, requestID).Observe(rand.Float64())

		dataSize := rand.Float64() * 5000
		userDataProcessed.WithLabelValues(userID, "json", "read", "api").Add(dataSize)

